package worldcup

import (
	"strings"

	"github.com/charmbracelet/lipgloss"
)

// RenderPixelFlag renders a country flag as colored ASCII art using the ▀
// half-block technique: each terminal cell shows two pixel rows at once
// (foreground = top pixel, background = bottom pixel).
// The rendered flag is 25 columns wide and 7 terminal rows tall (14 source pixels).
// Returns empty string when no pixel data exists for the given code.
func RenderPixelFlag(countryCode string) string {
	data, ok := pixelFlagData[strings.ToUpper(countryCode)]
	if !ok {
		return ""
	}

	const height = 14
	var b strings.Builder
	for y := 0; y < height; y += 2 {
		if y >= height-1 {
			continue
		}
		for x := 0; x < 25; x++ {
			top := data[y][x]
			bot := data[y+1][x]
			b.WriteString(lipgloss.NewStyle().
				SetString("▀").
				Foreground(lipgloss.Color(top)).
				Background(lipgloss.Color(bot)).
				String())
		}
		b.WriteString("\n")
	}
	return b.String()
}

